mapper.select:
SELECT started_at
  FROM response_session
 WHERE form_id = #{formId}
   AND respondent_id = #{respondentId}

mapper.delete:
DELETE FROM response_session
 WHERE form_id = #{formId}
   AND respondent_id = #{respondentId}

mapper.select:
SELECT COUNT(1)
  FROM survey_response
 WHERE form_id = #{formId}
   AND respondent_id = #{respondentId}

SELECT id            AS "responseId",
       respondent_id AS "respondentId",
       quality_flag  AS "qualityFlag"
  FROM survey_response
 WHERE id = #{responseId}
   AND form_id = #{formId}

mapper.update:
UPDATE survey_response
   SET quality_flag = #{qualityFlag}
 WHERE id = #{responseId}
   AND form_id = #{formId}

mapper.select:
SELECT quality_flag
  FROM survey_response
 WHERE form_id = #{formId}
 ORDER BY submitted_at DESC
 LIMIT #{limit}
